const r={};r.setCookie=(e,o,i)=>{const t=new Date;t.setTime(t.getTime()+i*60*60*1e3);const c="expires"+t.toUTCString();document.cookie=`${e}=${o}; ${c}; path=/ ;SameSite=Strict`};r.checkCookieExists=e=>{const o=document.cookie.split(";");for(let i=0;i<o.length;i++)if(o[i].trim().indexOf(e+"=")===0)return!0;return!1};r.getCookieValue=e=>{const o=e+"=",t=decodeURIComponent(document.cookie).split(";");for(let c=0;c<t.length;c++){let n=t[c];for(;n.charAt(0)===" ";)n=n.substring(1);if(n.indexOf(o)===0)return n.substring(o.length,n.length)}return null};r.removeCookie=e=>{document.cookie=e+"=; expires=Thu, 01 Jan 1970 00:00:00UTC; path=/; SameSite=Strict"};export{r as u};
